// Simulated external package. Living under node_modules means the discovery
// classifies these members as INHERITED — exactly how @types/react's
// ButtonHTMLAttributes behaves in a real target repo.
export interface ButtonHTMLAttributes<T> {
  onClick?: (event: T) => void
  disabled?: boolean
  type?: 'button' | 'submit' | 'reset'
  children?: unknown
}
